{"content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.EOL_CHAR
import org.junit.jupiter.api.Test

class BinaryExpressionWrappingRuleReproTest {
    private val binaryExpressionWrappingRuleAssertThat = KtLintAssertThat.assertThatRule { BinaryExpressionWrappingRule() }

    @Test
    fun `Given a binary expression with elvis operator on new line followed by a long throw expression`() {
        val code =
            """
            // 60 chars marker                                          $EOL_CHAR
            val foo =
                bar
                    ?:
                    throw UnsupportedOperationException("xxxxxxxxxxx")
            """.trimIndent()

        binaryExpressionWrappingRuleAssertThat(code)
            .addAdditionalRuleProvider { ChainWrappingRule() }
            .withEditorConfigOverride {
                properties["max_line_length"] = "60"
            }
            // If the loop exists, the formatter will report that it cannot resolve all violations in limited runs
            // The expectation here is that it SHOULD be stable.
            // Since we can't easily assert "does not loop", we assert the result.
            // If it loops, the test framework usually fails with "Format was not able to resolve all violations..."
            .hasLintViolationWithoutAutoCorrect(5, 21, "Line is exceeding max line length")
    }
}
